def priority(job, proc_times, sequence):
    # Heuristic parameters (tunable in practice)
    lambda1 = 1.0
    lambda2 = 1.0
    lambda3 = 1.0

    n_jobs = len(proc_times)
    if n_jobs == 0:
        return 0.0

    m = len(proc_times[0]) if n_jobs > 0 else 0
    if m == 0:
        return 0.0

    # Mark scheduled jobs
    scheduled = [False] * n_jobs
    for idx in sequence:
        if 0 <= idx < n_jobs:
            scheduled[idx] = True

    # Remaining load on each machine (including the candidate)
    D = [0.0] * m
    for i in range(n_jobs):
        if not scheduled[i]:
            times = proc_times[i]
            for k in range(m):
                D[k] += times[k]

    # Candidate job processing times
    if not (0 <= job < n_jobs):
        raise ValueError("Invalid job index")

    p_j_times = proc_times[job]
    p_j_total = sum(p_j_times)
    p_j1 = p_j_times[0] if m > 0 else 0.0

    # Downstream congestion term: sum over machines 2..m of p_jk * D_k
    downstream = 0.0
    for k in range(1, m):
        downstream += p_j_times[k] * D[k]

    # Priority score
    score = lambda1 * p_j_total - lambda2 * p_j1 + lambda3 * downstream
    return float(score)
